#include <bits/stdc++.h>
using namespace std;

const int N=110;

int d[8][2]={{1,2},{1,-2},{-1,2},{-1,-2},{2,1},{-2,1},{2,-1},{-2,-1}};
int n,m,t,match[N*N],ans;
bool b[N][N],vis[N*N];
vector<int> g[N*N];

int cal(int x,int y){
    return (x-1)*m+y;
}

bool dfs(int x){
    for(int y:g[x])
        if(!vis[y]){
            vis[y]=1;
            if(!match[y] || dfs(match[y])){
                match[y]=x;
                return 1;
            }
        }
    return 0;
}

int main(){
    scanf("%d%d%d",&n,&m,&t);
    for(int i=0;i<t;i++){
        int x,y;
        scanf("%d%d",&x,&y);
        b[x][y]=1;
    }
    for(int i=1;i<=n;i++)
        for(int j=i%2+1;j<=m;j+=2){
            if(b[i][j])
                continue;
            for(int k=0;k<8;k++){
                int x=i+d[k][0],y=j+d[k][1];
                if(x<1 || x>n || y<1 || y>m || b[x][y])
                    continue;
                g[cal(i,j)].push_back(cal(x,y));
            }
        }
    for(int i=1;i<=n;i++)
        for(int j=i%2+1;j<=m;j+=2){
            if(b[i][j])
                continue;
            memset(vis,0,sizeof(vis));
            if(dfs(cal(i,j)))
                ans++;
        }
    printf("%d",n*m-t-ans);
    return 0;
}
